def modify_ifc(model):
    import ifcopenshell
    import ifcopenshell.api

    changes = []

    storeys = model.by_type('IfcBuildingStorey')
    if len(storeys) < 2:
        raise ValueError('Need at least 2 storeys to move elements between them')
    target = storeys[-1]

    windows = list(model.by_type('IfcWindow'))
    if not windows:
        raise ValueError('No IfcWindow entities found in model')

    for w in windows:
        old_name = '(unknown)'
        for rel in (w.ContainedInStructure or ()):
            if rel.RelatingStructure is not None:
                old_name = rel.RelatingStructure.Name or '(unnamed storey)'
                break
        ifcopenshell.api.run('spatial.assign_container', model, products=[w], relating_structure=target)
        changes.append({'global_id': w.GlobalId, 'entity_name': w.Name or '(unnamed)', 'ifc_type': 'IfcWindow', 'description': f'Moved from storey {old_name} to {target.Name}', 'old_value': f'storey: {old_name}', 'new_value': f'storey: {target.Name}'})

    return {'summary': f'Moved {len(changes)} IfcWindow entities to storey {target.Name}', 'changes': changes}
